        </div>
    `;
    return eventElement;
}

function appendEvents() {
    eventsContainer.innerHTML = '';
    timelineData.events.forEach((event) => {
        const eventElement = createEventElement(event);
        eventsContainer.appendChild(eventElement);
    });
}

appendEvents();
